class MonolithicAnalyticsEngine:
    def __init__(self):
        self.metrics = {'clicks': 0, 'views': 0, 'purchases': 0, 'revenue': 0.0}
        self.parsed_events = []
        print("Analytics Engine Started.")

    def parse_raw_stream(self, raw_strings):
        print("Parsing raw JSON stream...")
        for raw in raw_strings:
            try:
                parsed = json.loads(raw)
                self.parsed_events.append(parsed)
            except Exception:
                # Subtle Bug: Bare exception. If JSON is malformed, it silently skips it.
                # Over time, millions of events could be lost with zero logs.
                pass

    def purge_bot_traffic(self):
        print("Purging bot traffic from parsed events...")
        # Logical Bug: Mutating list while iterating
        for event in self.parsed_events:
            ua = event.get('user_agent', '')
            if 'bot' in ua.lower() or 'spider' in ua.lower():
                self.parsed_events.remove(event) # Skips the next event in the array!

    def process_event_stream(self):
        print("Processing cleaned event stream...")

        # Resource Leak: Unclosed file handle inside a heavy processing loop.
        report_file = open(f"daily_report_{int(time.time())}.csv", "w")
        report_file.write("Timestamp,EventType,UserID,Value
")

        # Massive Cyclomatic Complexity & DRY Violations
        for event in self.parsed_events:
            if event is not None:
                if 'event_type' in event:
                    e_type = event['event_type']

                    if e_type == 'event_click':
                        if 'user_id' in event:
                            if event['user_id'] is not None:
                                if 'timestamp' in event:
                                    # DRY Violation block 1
                                    self.metrics['clicks'] += 1
                                    report_file.write(f"{event['timestamp']},{e_type},{event['user_id']},0
")
                                    print(f"Processed click for user {event['user_id']}")

                    elif e_type == 'event_view':
                        if 'user_id' in event:
                            if event['user_id'] is not None:
                                if 'timestamp' in event:
                                    # DRY Violation block 2: Exact same structure
                                    self.metrics['views'] += 1
                                    report_file.write(f"{event['timestamp']},{e_type},{event['user_id']},0
")
                                    print(f"Processed view for user {event['user_id']}")

                    elif e_type == 'event_purchase':
                        if 'user_id' in event:
                            if event['user_id'] is not None:
                                if 'timestamp' in event:
                                    if 'amount' in event:
                                        if event['amount'] > 0:
                                            # DRY Violation block 3: Same structure, slightly different math
                                            self.metrics['purchases'] += 1
                                            self.metrics['revenue'] += event['amount']
                                            report_file.write(f"{event['timestamp']},{e_type},{event['user_id']},{event['amount']}
")
                                            print(f"Processed purchase for user {event['user_id']} : ${event['amount']}")
                                        else:
                                            print("Invalid amount")
                                    else:
                                        print("Missing amount")

                    elif e_type == 'event_refund':
                        if 'user_id' in event:
                            if event['user_id'] is not None:
                                if 'timestamp' in event:
                                    if 'amount' in event:
                                        if event['amount'] > 0:
                                            # DRY Violation block 4
                                            self.metrics['revenue'] -= event['amount']
                                            report_file.write(f"{event['timestamp']},{e_type},{event['user_id']},-{event['amount']}
")
                                            print(f"Processed refund for user {event['user_id']} : -${event['amount']}")
                                        else:
                                            print("Invalid amount")
                                    else:
                                        print("Missing amount")
                    else:
                        print("Unknown event type")
                else:
                    print("Missing event type")
            else:
                print("Event is None")

        # report_file.close() is missing!
        print("Stream processing complete.")

